<?php namespace App\Repositories\Academic;use App\Repositories\BaseRepository;use App\Models\Academic\StudyMaterial;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class StudyMaterialRepository extends BaseRepository{    public function __construct(StudyMaterial $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function findBySubject(int $subjectId): Collection    {        return $this->findByField('subject_id', $subjectId);    }    public function findByTeacher(int $employeeId): Collection    {        return $this->findByField('employee_id', $employeeId);    }    public function findByType(string $type): Collection    {        return $this->findByField('material_type', $type);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('created_at', [$startDate, $endDate])->get();    }    public function searchMaterials(string $keyword): Collection    {        return $this->query()->where('title', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->orWhere('tags', 'like', "%{$keyword}%")->get();    }    public function getByClassAndSubject(int $classId, int $subjectId): Collection    {        return $this->query()->where('class_id', $classId)->where('subject_id', $subjectId)->orderBy('created_at', 'desc')->get();    }    public function getRecentMaterials(int $limit = 10): Collection    {        return $this->query()->orderBy('created_at', 'desc')->limit($limit)->get();    }    public function getByTags(string $tags): Collection    {        return $this->query()->where('tags', 'like', "%{$tags}%")->get();    }    public function incrementDownloadCount(int $id): bool    {        return $this->query()->where('id', $id)->increment('download_count');    }}